class Solution:
    def maxBook(self, seats, students):
        students_placed = 0
        for i, student in enumerate(students):
            for j, seat in enumerate(seats):
                if student[1] <= seat[1] or seat[1] == -1:
                    students_placed += 1
                    seat[1] = student[1]
                    break
        return students_placed


if __name__ == '__main__':
    solution = Solution()
    seats = [[5,3],[2,4]]
    students = [[4,5],[2,6]]
    print(solution.maxBook(seats, students))

