#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
int maxBook(vector<vector<int>> seats, vector<vector<int>> students) {
	int studentsPlaced = 0;
	for(int i = 0; i < students.size(); i++) {
		for(int j = 0; j < seats.size(); j++) {
			if(students[i][1] <= seats[j][1]) {
				studentsPlaced++;
				break;
			}
		}
	}
	return studentsPlaced;
}
};

int main() {
	Solution solution;
	vector<vector<int>> seats = {{5,3},{2,4}};
	vector<vector<int>> students = {{4,5},{2,6}};
	cout << solution.maxBook(seats, students);
	return 0;
}
